    public interface IBlockchainService
    {
        Task<bool> SaveFile(string fileName, string contentType, double length, string hash);

        Task<bool> ValidateHash(string fileName, string contentType, double length, string hash);

        Task<bool> DeleteFile(string hash);
    }

    public class BlockchainService : IBlockchainService
    {
        public async Task<bool> SaveFile(string fileName, string contentType, double length, string hash)
        {
            string url = "https://polygon-amoy.g.alchemy.com/v2/42PV15dvSMFZ0tXs5De5nb-NTSFDqmix";
            string privateKey = "e195014728dabd263710ed34922439790d5c992e01ebec69b40825bdc5efef4d";
            Account account = new Account(privateKey);
            Web3 web3 = new Web3(account, url);

            //var fileRegistryRecruitmentDeployment = new FileRegistryRecruitmentDeployment();

            //var transactionReceiptDeployment = await web3.Eth.GetContractDeploymentHandler<FileRegistryRecruitmentDeployment>().SendRequestAndWaitForReceiptAsync(fileRegistryRecruitmentDeployment);
            //var contractAddress = transactionReceiptDeployment.ContractAddress;

            ContractHandler contractHandler = web3.Eth.GetContractHandler("0xaAE2350cEDb0B8E7ce96b1d131449f25421FC4a3");

            try
            {
                StoreFileFunction storeFileFunction = new StoreFileFunction()
                {
                    FileHash = hash,
                    FileName = fileName,
                    FileType = contentType,
                    UploadedBy = "",
                    FileSize = (int)length
                };

                TransactionReceipt storeFileFunctionTxnReceipt = await contractHandler.SendRequestAndWaitForReceiptAsync(storeFileFunction);

                return true;
            }
            catch (Exception ex)
            {
                return false;
            }
        }

        public async Task<bool> ValidateHash(string fileName, string contentType, double length, string hash)
        {
            string url = "https://polygon-amoy.g.alchemy.com/v2/42PV15dvSMFZ0tXs5De5nb-NTSFDqmix";
            string privateKey = "e195014728dabd263710ed34922439790d5c992e01ebec69b40825bdc5efef4d";
            Account account = new Account(privateKey);
            Web3 web3 = new Web3(account, url);

            ContractHandler contractHandler = web3.Eth.GetContractHandler("0xaAE2350cEDb0B8E7ce96b1d131449f25421FC4a3");

            try
            {
                VerifyFileFunction verifyFileFunction = new VerifyFileFunction()
                {
                    FileHash = hash,
                    FileName = fileName,
                    FileType = contentType,
                    UploadedBy = "",
                    FileSize = (int)length
                };

                TransactionReceipt verifyFileFunctionTxnReceipt = await contractHandler.SendRequestAndWaitForReceiptAsync(verifyFileFunction);

                return true;
            }
            catch (Exception ex)
            {
                return false;
            }
        }

        public async Task<bool> DeleteFile(string hash)
        {
            string url = "https://polygon-amoy.g.alchemy.com/v2/42PV15dvSMFZ0tXs5De5nb-NTSFDqmix";
            string privateKey = "e195014728dabd263710ed34922439790d5c992e01ebec69b40825bdc5efef4d";
            Account account = new Account(privateKey);
            Web3 web3 = new Web3(account, url);

            ContractHandler contractHandler = web3.Eth.GetContractHandler("0xaAE2350cEDb0B8E7ce96b1d131449f25421FC4a3");

            try
            {
                DeleteFileFunction deleteFileFunction = new DeleteFileFunction()
                {
                    FileHash = hash,
                };

                TransactionReceipt verifyFileFunctionTxnReceipt = await contractHandler.SendRequestAndWaitForReceiptAsync(deleteFileFunction);

                return true;
            }
            catch (Exception ex)
            {
                return false;
            }
        }
    }

