    public partial class DeleteFileFunction : DeleteFileFunctionBase { }

    [Function("deleteFile")]
    public class DeleteFileFunctionBase : FunctionMessage
    {
        [Parameter("string", "_fileHash", 1)]
        public virtual string FileHash { get; set; }
    }

    public partial class StoreFileFunction : StoreFileFunctionBase { }

    [Function("storeFile")]
    public class StoreFileFunctionBase : FunctionMessage
    {
        [Parameter("string", "_fileHash", 1)]
