        [Parameter("string", "_fileName", 2)]
        public virtual string FileName { get; set; }

        [Parameter("string", "_fileType", 3)]
        public virtual string FileType { get; set; }

        [Parameter("string", "_uploadedBy", 4)]
        public virtual string UploadedBy { get; set; }

        [Parameter("uint256", "_fileSize", 5)]
        public virtual BigInteger FileSize { get; set; }
    }

